var raw = $input.first().json;
var body = raw.body || raw;
var tenantId = String(body.tenantId || '');
var fecId = String(body.fecId || '');

var UUID_RE = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;

if (!tenantId || !UUID_RE.test(tenantId)) {
  throw new Error('tenantId requis et doit être un UUID valide');
}
if (!fecId || !UUID_RE.test(fecId)) {
  throw new Error('fecId requis et doit être un UUID valide');
}

return [{
  json: {
    tenantId: tenantId,
    fecId: fecId
  }
}];

var fecData = $('05. Get FEC').first();
var ecrituresData = $('06. Get Ecritures').all();

if (!fecData || !fecData.json || !fecData.json.id) {
  return [{ json: { error: 'FEC not found' } }];
}

var fec = fecData.json;
var fecLines = [];

var headerRow = [
  'JournalCode', 'JournalLib', 'EcritureNum', 'EcritureDate',
  'CompteNum', 'CompteLib', 'CompAuxNum', 'CompAuxLib',
  'PieceRef', 'PieceDate', 'EcritureLib', 'Debit', 'Credit',
  'EcrLettrage', 'DateLettrage', 'ValidDate', 'MontantDevise', 'Idevise'
];
fecLines.push(headerRow);

ecrituresData.forEach(function(item) {
  var e = item.json;
  if (e.lines && Array.isArray(e.lines)) {
    e.lines.forEach(function(line) {
      if (line) {
        fecLines.push([
          e.journal_code || '',
          e.journal_lib || '',
          e.numero || '',
          e.date_ecriture ? e.date_ecriture.substring(0, 10) : '',
          line.compte_num || '',
          line.compte_lib || '',
          line.comp_aux_num || '',
          line.comp_aux_lib || '',
          line.piece_ref || '',
          line.piece_date ? line.piece_date.substring(0, 10) : '',
          e.libelle || '',
          line.debit || 0,
          line.credit || 0,
          line.ecr_lettrage || '',
          line.date_lettrage ? line.date_lettrage.substring(0, 10) : '',
          new Date().toISOString().substring(0, 10),
          line.montant_devise || 0,
          line.idevise || 'EUR'
        ]);
      }
    });
  }
});

var content = fecLines.map(function(row) {
  return row.map(function(cell) {
    return String(cell).trim();
  }).join('\t');
}).join('\n');

var buffer = Buffer.from(content, 'utf8');
var base64Content = buffer.toString('base64');

return [{
  json: {
    content: base64Content,
    contentPlain: content,
    filename: fec.nom_fichier,
    format: fec.format,
    size: buffer.length,
    fecId: fec.id,
    tenantId: $json.tenantId
  }
}];

var exportData = $('07. Build Export').first().json;

if (!exportData || !exportData.content) {
  return [{ json: { success: false, error: 'Export failed' } }];
}

return [{
  json: {
    success: true,
    content: exportData.content,
    filename: exportData.filename,
    format: exportData.format,
    size: exportData.size,
    encoding: 'base64',
    mimeType: exportData.format === 'xml' ? 'application/xml' : 'text/plain'
  }
}];
